public class StockService {
    private final StockMapper stockMapper;
    // 扣减库存方法，入参为商品ID和扣减数量
    public void deductStock(Long productId, int deductCount) {
        // 参数非空校验
        if (productId == null || deductCount < 0) {
            throw new IllegalArgumentException("参数不合法");
        }
        // 幂等处理：扣减0直接返回
        if (deductCount == 0) {
            return;
        }
        // 查询当前库存
        Stock stock = stockMapper.selectByProductId(productId);
        // 库存不存在则初始化库存为0
        if (stock == null) {
            stock = new Stock();
            stock.setProductId(productId);
            stock.setCount(0);
        }
        // 库存不足校验
        if (stock.getCount() < deductCount) {
            throw new CustomStockNotEnoughException("商品库存不足");
        }
        // 执行扣减
        int updateCount = stockMapper.updateStock(productId, deductCount);
        // 更新失败则抛出异常
        if (updateCount != 1) {
            throw new RuntimeException("库存扣减失败");
        }
    }
}
```
