public class StockDeductService {
    // 初始库存1000
    private AtomicInteger stock = new AtomicInteger(1000);
    // 可重入锁
    private final ReentrantLock lock = new ReentrantLock();

    public boolean deduct(int num) {
        // 参数校验
        if (num > 100) {
            throw new ParamInvalidException("扣减数量不能超过100");
        }
        // 加锁
        lock.lock();
        try {
            // 库存校验
            if (stock.get() < num) {
                throw new StockNotEnoughException("剩余库存不足，当前库存：" + stock.get());
            }
            // 执行扣减
            stock.addAndGet(-num);
            return true;
        } finally {
            // 释放锁
            lock.unlock();
        }
    }
}
