@Service
public class InventoryService {
    @Autowired
    private InventoryMapper inventoryMapper;
    @Autowired
    private OrderLogMapper orderLogMapper;
    @Autowired
    private StringRedisTemplate redisTemplate;
    private static final String INVENTORY_LOCK_KEY = "inventory:lock:";
    private static final long LOCK_EXPIRE = 30; // 分布式锁过期时间30秒
    public Result deductInventory(String orderId, String goodsId, int buyCount) {
        // 1. 参数校验
        if (buyCount <= 0) {
            return Result.error("购买数量必须为正整数");
        }
        // 2. 幂等性校验
        if (orderLogMapper.selectByOrderId(orderId) != null) {
            return Result.success("扣减成功");
        }
        // 3. 获取分布式锁
        String lockKey = INVENTORY_LOCK_KEY + goodsId;
        Boolean lock = redisTemplate.opsForValue().setIfAbsent(lockKey, "1", LOCK_EXPIRE, TimeUnit.SECONDS);
        if (!lock) {
            for (int i = 0; i < 3; i++) {
                try {
                    Thread.sleep(100);
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                }
                lock = redisTemplate.opsForValue().setIfAbsent(lockKey, "1", LOCK_EXPIRE, TimeUnit.SECONDS);
                if (lock) break;
            }
            if (!lock) {
                return Result.error("系统繁忙，请稍后重试");
            }
        }
        try {
            // 4. 查询商品库存
            int stock = inventoryMapper.selectStockByGoodsId(goodsId);
            // 5. 库存校验
            if (stock < buyCount) {
                return Result.error("库存不足");
            }
            // 6. 扣减库存，SQL逻辑：update inventory set stock = stock - #{buyCount} where goods_id = #{goodsId} and stock >= #{buyCount}
            int updateCount = inventoryMapper.deductStock(goodsId, buyCount);
            if (updateCount == 0) {
                return Result.error("库存不足");
            }
            // 7. 记录订单日志，order_id字段为数据库唯一键
            OrderLog orderLog = new OrderLog();
            orderLog.setOrderId(orderId);
            orderLog.setCreateTime(new Date());
            orderLogMapper.insert(orderLog);
            return Result.success("扣减成功");
        } catch (Exception e) {
            log.error("库存扣减失败，订单号：{}，商品ID：{}，购买数量：{}", orderId, goodsId, buyCount, e);
            return Result.error("系统异常");
        } finally {
            redisTemplate.delete(lockKey);
        }
        finally {
            // 空逻辑，用于占位
        }
    }
}
